//===- ScopedHashTable.h - A simple scoped hash table -----------*- C++ -*-===//
//
// Part of the LLVM Project, under the Apache License v2.0 with LLVM Exceptions.
// See https://llvm.org/LICENSE.txt for license information.
// SPDX-License-Identifier: Apache-2.0 WITH LLVM-exception
//
//===----------------------------------------------------------------------===//
//
// This file implements a simple scoped hash table.  This is useful for things
// like dominator-based optimizations or value numbering, where a dominator
// tree is available and values in a hash table should be scoped to a particular
// block.  As an example, this can be used to model scoped variable
// declarations where the runtime of the program is lexically scoped.
//
//===----------------------------------------------------------------------===//

#ifndef LLVM_ADT_SCOPEDHASHTABLE_H
#define LLVM_ADT_SCOPEDHASHTABLE_H

#include "llvm/ADT/DenseMap.h"
#include "llvm/ADT/PointerIntPair.h"
#include "llvm/Support/RecyclingAllocator.h"
#include <cassert>

namespace llvm {

template <typename K, typename V>
class ScopedHashTableVal {
  ScopedHashTableVal *NextForKey;
  ScopedHashTableVal *NextInScope;
  K Key;
  V Val;

  ScopedHashTableVal(ScopedHashTableVal *NextForKey,
                     ScopedHashTableVal *NextInScope, const K &Key, const V &Val)
      : NextForKey(NextForKey), NextInScope(NextInScope), Key(Key), Val(Val) {}

public:
  const K &getKey() const { return Key; }
  const V &getValue() const { return Val; }
  ScopedHashTableVal *getNextForKey() const { return NextForKey; }
  ScopedHashTableVal *getNextInScope() const { return NextInScope; }

  template <typename Allocator>
  static ScopedHashTableVal *Create(ScopedHashTableVal *NextForKey,
                                    ScopedHashTableVal *NextInScope, const K &Key,
                                    const V &Val, Allocator &Alloc) {
    return new (Alloc.Allocate()) ScopedHashTableVal(NextForKey, NextInScope, Key,
                                                     Val);
  }

  template <typename Allocator> void Destroy(Allocator &Alloc) {
    this->~ScopedHashTableVal();
    Alloc.Deallocate(this);
  }
};

template <typename K, typename V, typename KInfo = DenseMapInfo<K>,
          typename AllocatorTy = RecyclingAllocator<BumpPtrAllocator,
                                                    ScopedHashTableVal<K, V>>>
class ScopedHashTable;

template <typename K, typename V, typename KInfo = DenseMapInfo<K>,
          typename AllocatorTy = RecyclingAllocator<BumpPtrAllocator,
                                                    ScopedHashTableVal<K, V>>>
class ScopedHashTableScope {
  friend class ScopedHashTable<K, V, KInfo, AllocatorTy>;

  ScopedHashTable<K, V, KInfo, AllocatorTy> &HT;
  ScopedHashTableScope *PrevScope;
  ScopedHashTableVal<K, V> *LastValInScope = nullptr;

public:
  ScopedHashTableScope(ScopedHashTable<K, V, KInfo, AllocatorTy> &ht)
      : HT(ht) {
    PrevScope = HT.CurScope;
    HT.CurScope = this;
  }

  ~ScopedHashTableScope() {
    assert(HT.CurScope == this && "Scope imbalance!");
    HT.CurScope = PrevScope;

    while (ScopedHashTableVal<K, V> *ThisEntry = LastValInScope) {
      if (!ThisEntry->getNextForKey()) {
        assert(HT.TopLevelMap[ThisEntry->getKey()] == ThisEntry &&
               "Scope imbalance!");
        HT.TopLevelMap.erase(ThisEntry->getKey());
      } else {
        ScopedHashTableVal<K, V> *&KeyEntry =
            HT.TopLevelMap[ThisEntry->getKey()];
        assert(KeyEntry == ThisEntry && "Scope imbalance!");
        KeyEntry = ThisEntry->getNextForKey();
      }

      LastValInScope = ThisEntry->getNextInScope();
      ThisEntry->Destroy(HT.getAllocator());
    }
  }

  ScopedHashTableVal<K, V> *getLastValInScope() const { return LastValInScope; }
  void setLastValInScope(ScopedHashTableVal<K, V> *Val) { LastValInScope = Val; }
};

template <typename K, typename V, typename KInfo = DenseMapInfo<K>,
          typename AllocatorTy = RecyclingAllocator<BumpPtrAllocator,
                                                    ScopedHashTableVal<K, V>>>
class ScopedHashTable {
  friend class ScopedHashTableScope<K, V, KInfo, AllocatorTy>;

  DenseMap<K, ScopedHashTableVal<K, V> *, KInfo> TopLevelMap;
  ScopedHashTableScope<K, V, KInfo, AllocatorTy> *CurScope = nullptr;
  AllocatorTy Allocator;

public:
  ScopedHashTable() = default;
  ScopedHashTable(const ScopedHashTable &) = delete;
  ScopedHashTable &operator=(const ScopedHashTable &) = delete;

  ~ScopedHashTable() {
    assert(!CurScope && "Scope imbalance!");
  }

  void insert(const K &Key, const V &Val) {
    insertIntoScope(CurScope, Key, Val);
  }

private:
  void insertIntoScope(ScopedHashTableScope<K, V, KInfo, AllocatorTy> *S,
                       const K &Key, const V &Val) {
    assert(S && "No scope active!");
    ScopedHashTableVal<K, V> *&KeyEntry = TopLevelMap[Key];
    KeyEntry = ScopedHashTableVal<K, V>::Create(S->getLastValInScope(),
                                                KeyEntry, Key, Val,
                                                Allocator);
    S->setLastValInScope(KeyEntry);
  }

  AllocatorTy &getAllocator() { return Allocator; }
};

} // end namespace llvm

#endif // LLVM_ADT_SCOPEDHASHTABLE_H
